#!/usr/bin/env python3
# Scaling trend of the resonance semantic key across rwkv7 sizes (0.1B/0.4B).
# Compares within-group vs across-group activation cosine separation on the COMMON
# prompt subset (g1-g4 x 3 phrasings). Usage: scaling-trend-analysis.py acts_A.json acts_B.json
import json, sys, numpy as np
from itertools import combinations
GROUPS=['g1_paris','g2_math','g3_sky','g4_freeze']
def load(f):
    d=json.load(open(f)); return d['records'], d['hidden_dim']
def cos(a,b): return float(a@b/(np.linalg.norm(a)*np.linalg.norm(b)))
def analyze(name, recs, D, common):
    s={g:[np.array(x['activation'],float) for x in recs if x['group']==g and x['text'] in common[g]] for g in GROUPS}
    within=np.array([cos(a,b) for g in GROUPS for a,b in combinations(s[g],2)])
    across=np.array([cos(s[gi][ai],s[gj][aj]) for i,gi in enumerate(GROUPS) for gj in GROUPS[i+1:] for ai in range(len(s[gi])) for aj in range(len(s[gj]))])
    acc=100*sum(w>a for w in within for a in across)/(len(within)*len(across))
    print(f"{name} D={D}: sep={within.mean()-across.mean():+.3f} ordering-acc={acc:.1f}% clean-margin={within.min()-across.max():+.3f}")
    return within.mean()-across.mean(), acc
rA,DA=load(sys.argv[1]); rB,DB=load(sys.argv[2])
tx=lambda r,g:set(x['text'] for x in r if x['group']==g)
common={g:tx(rA,g)&tx(rB,g) for g in GROUPS}
analyze(sys.argv[1],rA,DA,common); analyze(sys.argv[2],rB,DB,common)
